from __future__ import annotations

from typing import TypeAlias

from queryweave.parser.ast_nodes import (
    AggregateExpr,
    AliasExpr,
    Assignment,
    BetweenExpr,
    BinaryExpr,
    CaseExpr,
    ColumnDef,
    ColumnRef,
    CreateTableStmt,
    DeleteStmt,
    DropTableStmt,
    ExistsExpr,
    Expression,
    FrameBound,
    FunctionCall,
    GroupByClause,
    HavingClause,
    InExpr,
    InsertStmt,
    IsNullExpr,
    JoinClause,
    LikeExpr,
    LimitClause,
    LiteralExpr,
    Node,
    OrderByClause,
    OrderByItem,
    SelectStmt,
    StarExpr,
    SubqueryExpr,
    TableRef,
    UnaryExpr,
    UnionStmt,
    UpdateStmt,
    WhenClause,
    WhereClause,
    WindowExpr,
    WindowFrame,
)
from queryweave.parser.lexer import Lexer, Token, TokenStream, TokenType


Statement: TypeAlias = (
    SelectStmt
    | UnionStmt
    | InsertStmt
    | UpdateStmt
    | DeleteStmt
    | CreateTableStmt
    | DropTableStmt
)


class ParserError(SyntaxError):
    """Raised when parser-level syntax validation fails."""

    def __init__(self, message: str, token: Token) -> None:
        self.line = token.line
        self.col = token.col
        self.token = token
        super().__init__(f"Parser error at L{token.line}:{token.col}: {message}")


class Parser:
    """Parse lexer tokens into QueryWeave AST nodes."""

    _AGGREGATES = {"COUNT", "SUM", "AVG", "MIN", "MAX"}
    _COMPARISON_OPS = {"=", "!=", "<>", "<", "<=", ">", ">="}
    _ADDITIVE_OPS = {"+", "-", "||"}
    _MULTIPLICATIVE_OPS = {"*", "/", "%"}
    _RESERVED_CLAUSE_TOKENS = {
        TokenType.FROM,
        TokenType.WHERE,
        TokenType.GROUP_BY,
        TokenType.GROUP,
        TokenType.HAVING,
        TokenType.ORDER_BY,
        TokenType.ORDER,
        TokenType.LIMIT,
        TokenType.OFFSET,
        TokenType.UNION,
        TokenType.JOIN,
        TokenType.LEFT,
        TokenType.RIGHT,
        TokenType.INNER,
        TokenType.FULL,
        TokenType.CROSS,
        TokenType.ON,
        TokenType.RPAREN,
        TokenType.COMMA,
        TokenType.SEMICOLON,
        TokenType.EOF,
    }

    def __init__(self, source: str | Lexer | TokenStream | list[Token]) -> None:
        if isinstance(source, TokenStream):
            self.tokens = source
        elif isinstance(source, Lexer):
            self.tokens = TokenStream(source.tokenize())
        elif isinstance(source, str):
            self.tokens = TokenStream(Lexer(source).tokenize())
        else:
            self.tokens = TokenStream(source)

    def parse(self) -> Statement:
        """Parse one complete statement and require full token consumption."""
        statement = self.parse_statement()
        self._match(TokenType.SEMICOLON)
        if not self._at_end():
            tok = self._current()
            raise self._error(f"Unexpected token {tok.value!r} after statement", tok)
        return statement

    def parse_statement(self) -> Statement:
        """Parse a SELECT, DML, or DDL statement."""
        if self._check(TokenType.SELECT):
            return self.parse_query_expression()
        if self._check(TokenType.INSERT):
            return self.parse_insert()
        if self._check(TokenType.UPDATE):
            return self.parse_update()
        if self._check(TokenType.DELETE):
            return self.parse_delete()
        if self._check(TokenType.CREATE):
            return self.parse_create_table()
        if self._check(TokenType.DROP):
            return self.parse_drop_table()

        tok = self._current()
        raise self._error(f"Expected statement, got {tok.value!r}", tok)

    def parse_query_expression(self) -> SelectStmt | UnionStmt:
        """Parse SELECT and right-associative UNION chains."""
        left = self.parse_select()
        if self._match(TokenType.UNION):
            all_ = self._match(TokenType.ALL) is not None
            right = self.parse_query_expression()
            return UnionStmt(left=left, right=right, all=all_)
        return left

    def parse_select(self) -> SelectStmt:
        """Parse a SELECT statement without consuming UNION."""
        self._expect(TokenType.SELECT)
