            return self._advance()
        return None

    def _expect_word(self, word: str) -> Token:
        if tok := self._match_word(word):
            return tok
        tok = self._current()
        raise self._error(f"Expected {word}", tok)

    def _check_word(self, *words: str) -> bool:
        tok = self._current()
        return tok.type == TokenType.IDENTIFIER and tok.value.upper() in words

    def _expect(self, token_type: TokenType) -> Token:
        tok = self._current()
        if tok.type != token_type:
            raise self._error(f"Expected {token_type.name}, got {tok.type.name} ({tok.value!r})", tok)
        return self._advance()

    def _match(self, *types: TokenType) -> Token | None:
        return self.tokens.match(*types)

    def _check(self, *types: TokenType) -> bool:
        return self.tokens.check(*types)

    def _advance(self) -> Token:
        return self.tokens.advance()

    def _current(self) -> Token:
        return self.tokens.current()

    def _at_end(self) -> bool:
        return self.tokens.at_end()

    def _error(self, message: str, token: Token) -> ParserError:
        return ParserError(message, token)


def parse(query: str) -> Statement:
    """Parse a SQL query string into an AST statement."""
    return Parser(Lexer(query)).parse()
